"""Async `AsyncAgent` class. Mirror of `_agent.Agent`.

Unlike sync `Agent`, the async surface has no global default client, so
all classmethods take an explicit `client: AsyncClient` argument
(non-optional). The `AsyncAgent` <-> `AsyncClient` cycle is broken the
same way as the sync side: `_async_agent` imports `AsyncClient` for
typing only, and `_async_client` does its `AsyncAgent` constructions
through lazy imports inside `create_agent` / `resume_agent`.
"""

from __future__ import annotations

import os
from typing import TYPE_CHECKING, Any, Mapping

from ._async_run import AsyncRun
from ._helpers import (
    _api_key_or_env,
    _model_override_from_send_options,
    _options_with_api_key,
    _require_send_api_key_for_remote_cloud_agent,
)
from ._tool_callback import reject_send_local_custom_tools
from .types import (
    AgentMessage,
    AgentOptions,
    AsyncListResult,
    CloudAgentOptions,
    LocalAgentOptions,
    ModelSelection,
    RunResult,
    SDKAgentInfo,
    SdkArtifact,
    SendOptions,
    UserMessage,
    chunks_to_bytes,
    send_options_idempotency_key,
    send_options_to_json,
)

if TYPE_CHECKING:
    from ._async_client import AsyncClient


class _AsyncLifecycleMethod:
    """Dispatch async lifecycle calls by class or instance access."""

    def __init__(self, rpc_method: str) -> None:
        self._rpc_method = rpc_method

    def __get__(self, instance: "AsyncAgent | None", owner: type) -> Any:
        rpc = self._rpc_method
        if instance is None:

            async def class_form(
                agent_id: str,
                options: Mapping[str, Any] | None = None,
                *,
                client: "AsyncClient",
            ) -> None:
                await client._agent_unary(
                    rpc,
                    {"agentId": agent_id, "options": dict(options or {})},
                )

            return class_form

        agent = instance

        async def instance_form(options: Mapping[str, Any] | None = None) -> None:
            await agent._lifecycle_unary(rpc, options)

        return instance_form


class AsyncAgent:
    def __init__(
        self,
        *,
        client: "AsyncClient",
        agent_id: str,
        model: Mapping[str, Any] | ModelSelection | None,
        api_key: str | None = None,
    ) -> None:
        self.client = client
        self.agent_id = agent_id
        if model is None:
            self.model: ModelSelection | None = None
        elif isinstance(model, ModelSelection):
            self.model = model
        else:
            self.model = ModelSelection.from_json(dict(model))
        self._api_key = api_key or ""

    @classmethod
    async def create(
        cls,
        options: AgentOptions | Mapping[str, Any] | None = None,
        *,
        client: "AsyncClient",
        model: str | ModelSelection | Mapping[str, Any] | None = None,
        api_key: str | None = None,
        name: str | None = None,
        local: LocalAgentOptions | Mapping[str, Any] | None = None,
        cloud: CloudAgentOptions | Mapping[str, Any] | None = None,
        idempotency_key: str | None = None,
    ) -> "AsyncAgent":
        return await client.create_agent(
            options,
            model=model,
            api_key=api_key,
            name=name,
            local=local,
            cloud=cloud,
            idempotency_key=idempotency_key,
        )

    @classmethod
    async def resume(
        cls,
        agent_id: str,
        options: AgentOptions | Mapping[str, Any] | None = None,
        *,
        client: "AsyncClient",
    ) -> "AsyncAgent":
        return await client.resume_agent(agent_id, options)

    @classmethod
    async def prompt(
        cls,
        message: str | Mapping[str, Any] | UserMessage,
        options: AgentOptions | Mapping[str, Any] | None = None,
        *,
        client: "AsyncClient",
    ) -> RunResult:
        agent = await cls.create(options, client=client)
        try:
            run = await agent.send(message)
            return await run.wait()
        finally:
            await agent.close()

    @classmethod
    async def list(
        cls,
        options: Mapping[str, Any] | None = None,
        *,
        client: "AsyncClient",
    ) -> AsyncListResult[SDKAgentInfo]:
        return await client.list_agents(options)

    @classmethod
    async def get(
        cls,
        agent_id: str,
        *,
        client: "AsyncClient",
        cwd: str | os.PathLike[str] | None = None,
        api_key: str | None = None,
    ) -> SDKAgentInfo:
        return await client.get_agent(
            agent_id,
            cwd=cwd,
            api_key=_api_key_or_env(
                api_key, allow_env=client._allow_api_key_env_fallback
            ),
        )

    async def send(
        self,
        message: str | Mapping[str, Any] | UserMessage,
        options: SendOptions | Mapping[str, Any] | None = None,
        *,
        idempotency_key: str | None = None,
    ) -> "AsyncRun":
        _require_send_api_key_for_remote_cloud_agent(
            allow_env_fallback=self.client._allow_api_key_env_fallback,
            agent_id=self.agent_id,
            api_key=self._api_key,
        )
        idempotency_key = idempotency_key or send_options_idempotency_key(options)
        request_options = _options_with_api_key(
            self._api_key, send_options_to_json(options)
        )
        reject_send_local_custom_tools(request_options)
        request = {
            "agentId": self.agent_id,
            "message": UserMessage.from_value(message).to_json(),
            "options": request_options,
            "idempotencyKey": idempotency_key or "",
        }
        events = await self.client._agent_stream(
            "Send",
            request,
            skip_remote_cloud_guard=bool(self._api_key),
        )
        run = await AsyncRun._from_stream(
            client=self.client,
            agent_id=self.agent_id,
            event_stream=events,
            send_options=options if isinstance(options, SendOptions) else None,
            api_key=self._api_key,
        )
        model_override = _model_override_from_send_options(options)
        if model_override is not None:
            self.model = ModelSelection.from_json(model_override)
        return run

    async def reload(self) -> None:
        await self.client._agent_unary("ReloadAgent", {"agentId": self.agent_id})

    async def close(self) -> None:
        self.client._unregister_custom_tools(self.agent_id)
        await self.client._agent_unary("CloseAgent", {"agentId": self.agent_id})

    async def list_messages(
        self, options: Mapping[str, Any] | None = None
    ) -> list[AgentMessage]:
        response = await self.client._agent_unary(
            "ListAgentMessages",
            {
                "agentId": self.agent_id,
                "options": _options_with_api_key(self._api_key, options),
            },
            skip_remote_cloud_guard=bool(self._api_key),
        )
        return [AgentMessage.from_json(item) for item in response.get("messages", [])]

    async def list_artifacts(self) -> list[SdkArtifact]:
        response = await self.client._agent_unary(
            "ListArtifacts",
            {
                "agentId": self.agent_id,
                "options": _options_with_api_key(self._api_key),
            },
            skip_remote_cloud_guard=bool(self._api_key),
        )
        return [SdkArtifact.from_json(item) for item in response.get("artifacts", [])]

    async def download_artifact(self, path: str) -> bytes:
        chunks_iter = await self.client._agent_stream(
            "DownloadArtifact",
            {
                "agentId": self.agent_id,
                "path": path,
                "options": _options_with_api_key(self._api_key),
            },
            skip_remote_cloud_guard=bool(self._api_key),
        )
        # `chunks_to_bytes` accepts any iterable; convert async stream to list.
        chunks = [chunk async for chunk in chunks_iter]
        return chunks_to_bytes(chunks)

    async def _lifecycle_unary(
        self, method: str, options: Mapping[str, Any] | None
    ) -> None:
        await self.client._agent_unary(
            method,
            {
                "agentId": self.agent_id,
                "options": _options_with_api_key(self._api_key, options),
            },
            skip_remote_cloud_guard=bool(self._api_key),
        )

    async def __aenter__(self) -> "AsyncAgent":
        return self

    async def __aexit__(self, *exc: Any) -> None:
        await self.close()

    archive = _AsyncLifecycleMethod("ArchiveAgent")
    unarchive = _AsyncLifecycleMethod("UnarchiveAgent")
    delete = _AsyncLifecycleMethod("DeleteAgent")
